            if (pBuffer == in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
            {
                pOut =
                    nn_mat_mul_kernel_q7_q15_q7_reordered_bias_2sft(ker_weight,
                                                                    in_tmp_buf,
