        }
    }

    /* middle part, here we also divide the x into left, mid and right */
    for (; i_out_y < out_tensor_dim - pad; i_out_y++)
    {
        /* left part */
        for (i_out_x = 0; i_out_x < pad; i_out_x++)
        {
            /* This part implements the im2col function */
            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
            {
                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
                {
                    if (i_ker_x < 0 || i_ker_x >= in_tensor_dim)
                    {
                        memset(pBuffer, 0, sizeof(q15_t)*in_tensor_ch);
                    }
                    else
                    {
                        nn_dup_s8_s16_reordered
                        ((q7_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
                    }
                    pBuffer += in_tensor_ch;
                }
            }

            if (pBuffer == in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
            {
                pOut =
                    nn_mat_mul_kernel_q7_q15_q7_reordered_bias_2sft(ker_weight,
                                                                    in_tmp_buf,
                                                                    out_tensor_ch,
                                                                    in_tensor_ch * ker_dim * ker_dim,
                                                                    pre_rshift,
                                                                    out_scale,
                                                                    post_rshift,
                                                                    bias,
                                                                    pOut);
                /* counter reset */
                pBuffer = in_tmp_buf;
            }
        }

        /* mid part */
        for (; i_out_x < out_tensor_dim - pad; i_out_x++)
        {
            /* This part implements the im2col function */
            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
            {
                nn_dup_s8_s16_reordered((q7_t *) in_tensor + (i_ker_y * in_tensor_dim + i_out_x * stride - pad) * in_tensor_ch, pBuffer, in_tensor_ch * ker_dim);
                pBuffer += in_tensor_ch * ker_dim;
            }

            if (pBuffer == in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
            {
                pOut =
                    nn_mat_mul_kernel_q7_q15_q7_reordered_bias_2sft(ker_weight,
                                                                    in_tmp_buf,
                                                                    out_tensor_ch,
                                                                    in_tensor_ch * ker_dim * ker_dim,
                                                                    pre_rshift,
                                                                    out_scale,
                                                                    post_rshift,
                                                                    bias,
                                                                    pOut);
                /* counter reset */
                pBuffer = in_tmp_buf;
            }
        }

        /* right part */
        for (; i_out_x < out_tensor_dim; i_out_x++)
        {
            /* This part implements the im2col function */
            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
            {
                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
                {
                    if (i_ker_x < 0 || i_ker_x >= in_tensor_dim)
                    {
                        memset(pBuffer, 0, sizeof(q15_t)*in_tensor_ch);
                    }
                    else
                    {
                        nn_dup_s8_s16_reordered
                        ((q7_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
                    }
                    pBuffer += in_tensor_ch;
                }
            }

            if (pBuffer == in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
            {
                pOut =
                    nn_mat_mul_kernel_q7_q15_q7_reordered_bias_2sft(ker_weight,
                                                                    in_tmp_buf,
                                                                    out_tensor_ch,
                                                                    in_tensor_ch * ker_dim * ker_dim,
                                                                    pre_rshift,
                                                                    out_scale,
                                                                    post_rshift,
                                                                    bias,
                                                                    pOut);
                /* counter reset */
                pBuffer = in_tmp_buf;
            }
        }
    }

    for (; i_out_y < out_tensor_dim; i_out_y++)
    {
        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
        {
            /* This part implements the im2col function */
            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
            {
                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
                {
                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
                    {
                        memset(pBuffer, 0, sizeof(q15_t)*in_tensor_ch);
                    }
                    else
                    {
                        nn_dup_s8_s16_reordered
                        ((q7_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
                    }
                    pBuffer += in_tensor_ch;
                }
            }

            if (pBuffer == in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
            {
                pOut =
                    nn_mat_mul_kernel_q7_q15_q7_reordered_bias_2sft(ker_weight,
                                                                    in_tmp_buf,
                                                                    out_tensor_ch,
                                                                    in_tensor_ch * ker_dim * ker_dim,
                                                                    pre_rshift,
                                                                    out_scale,
                                                                    post_rshift,
                                                                    bias,
                                                                    pOut);
                /* counter reset */
                pBuffer = in_tmp_buf;
            }
        }
    }

    /* check if there is left-over for compute */
    if (pBuffer != in_tmp_buf)
    {
        const q7_t *pA = ker_weight;
        int       i;

        for (i = 0; i < out_tensor_ch; i++)
        {
            q31_t     sum = bias[i];
            q15_t    *pB = in_tmp_buf;
            /* each time it process 4 entries */
            uint16_t  colCnt = in_tensor_ch * ker_dim * ker_dim >> 2;

            while (colCnt)
            {
                q31_t     inA1, inA2;
                q31_t     inB1, inB2;

                pA = (q7_t *) read_and_pad_reordered((void *)pA, &inA1, &inA2);

                inB1 = *__SIMD32(pB)++;
                sum = NDS_DSP_KMADA(sum, inA1, inB1);
                inB2 = *__SIMD32(pB)++;
                sum = NDS_DSP_KMADA(sum, inA2, inB2);

                colCnt--;
            }
            //since in_tensor_ch is multiple of 4 (input constraints), the
            //following codes will not be reached
            // colCnt = in_tensor_ch * ker_dim * ker_dim & 0x3;
            // while (colCnt)
            // {
            //     q7_t      inA1 = *pA++;
            //     q15_t     inB1 = *pB++;
            //     sum += inA1 * inB1;
            //     colCnt--;
            // }
            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
            *pOut++ = NDS_DSP_SATS((sum >> post_rshift), 8);
        }
    }
#else
    uint16_t  i, j, k, l, m, n;
    int       conv_out;
    long in_row, in_col;

    for (i = 0; i < out_tensor_ch; i++)
    {
        for (j = 0; j < out_tensor_dim; j++)
        {
            for (k = 0; k < out_tensor_dim; k++)
            {
                conv_out = bias[i];
                for (m = 0; m < ker_dim; m++)
                {
                    for (n = 0; n < ker_dim; n++)
                    {
                        // if-for implementation
                        in_row = stride * j + m - pad;
                        in_col = stride * k + n - pad;
                        if (in_row >= 0 && in_col >= 0 && in_row < in_tensor_dim && in_col < in_tensor_dim)
                        {
                            for (l = 0; l < in_tensor_ch; l++)
                            {
                                conv_out +=
                                    in_tensor[(in_row * in_tensor_dim + in_col) * in_tensor_ch + l]
                                    * ker_weight[i * in_tensor_ch * ker_dim * ker_dim + (m * ker_dim + n) * in_tensor_ch + l];
                            }
                        }
                    }
                }
                conv_out = (conv_out >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
                out_tensor[i + (j * out_tensor_dim + k) * out_tensor_ch] = NDS_ISA_SATS((conv_out >> post_rshift), 8);
            }
        }
    }
#endif  //ENA_DSP_ISA
#endif  //ENA_EMPTY_FUN

    /* Return to application */
    return 0;
}

