    //small_matrix also use original_rvv
    unsigned int total = ((row * col) + (col * col2) + (row * col2)); //ABC size
    unsigned int max_size = tiling_size * tiling_size * 3; //max small_matrix size
    if(total < max_size)
    {
        rvv = RVV_ORIGINAL;
    }

#ifdef ENA_PACKING_HVM
    rvv = RVV_PACKING;
#endif

    if(rvv == RVV_ORIGINAL)
    {
        //original rvv
        vec_mat_mul_rvv_original_vq(src1, src2, tmp_out, row, col, col2);
    }
    else if(rvv == RVV_TILING)
    {
        /* initial output */
        nn_set_zero_s16((q15_t *)tmp_out, (row * col2 * 2));
        //4*4 by 4*vl
        vec_mat_mul_rvv_tiling_vq(src1, src2, tmp_out, row, col, col2, tiling_size);
    }
    else if(rvv == RVV_PACKING)
    {
        /* initial output */
        nn_set_zero_s16((q15_t *)tmp_out, (row * col2 * 2));
        //packing_rvv
        int status = vec_mat_mul_rvv_packing_vq(src1, src2, tmp_out, row, col, col2, tiling_size);
