709	static inline void vec_mat_mul_rvv_tiling_vq(const MM_TYPE_A* src1, const MM_TYPE_B* src2, MM_TYPE_VQ* dst, uint32_t row, uint32_t col, uint32_t col2, uint32_t tiling_size)
710	{
711	    //2*8 by 8*vl
712	    int row_2 = row >> 1;
713	    int max_row = row_2 << 1;
714	
715	    const MM_TYPE_A* A = src1;
716	    const MM_TYPE_B* B = src2;
717	    MM_TYPE_VQ* C = dst;
718	    int r, k, kk, cc, vl;
719	    int kk_tiling_size, cc_tiling_size, max_kk_tiling_size;
720	    const MM_TYPE_A * A11, * A21;
721	    const MM_TYPE_B * B11, * B21, * B31, * B41, * B51, * B61, * B71, * B81;
722	    MM_TYPE_VQ * C1, * C2;
723	    for (kk = 0; kk < col; kk += tiling_size)
724	    {
725	        kk_tiling_size = ((kk + tiling_size) > col ? col : (kk + tiling_size));
726	        if ((kk + tiling_size) <= col)
727	        {
728	            max_kk_tiling_size = kk_tiling_size - (tiling_size & 7);
729	        }
730	        else
731	        {
732	            max_kk_tiling_size = col - ((col - kk) & 7);
733	        }
734	        for (cc = 0; cc < col2; cc += tiling_size)
735	        {
736	            cc_tiling_size = ((cc + tiling_size) > col2 ? col2 : (cc + tiling_size));
737	            for (r = 0; r < max_row; r += 2)
738	            {
739	                int mulLen = cc_tiling_size - cc;
740	                while (mulLen > 0)
741	                {
742	                    NDS_VEC_VSETVLI(vl, mulLen, DEF_VTYPEVQ_SEW, NDS_VEC_VTYPE_LMUL_M8);
743	                    NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0); //sum
744	                    NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0); //sum
745	
746	                    A11 = A + r * col + kk;
747	                    A21 = A11 + col;
748	                    B11 = B + kk * col2 + cc_tiling_size - mulLen;
749	                    B21 = B11 + col2;
750	                    B31 = B21 + col2;
751	                    B41 = B31 + col2;
752	                    B51 = B41 + col2;
753	                    B61 = B51 + col2;
754	                    B71 = B61 + col2;
755	                    B81 = B71 + col2;
756	                    C1 = C + r * col2 + cc_tiling_size - mulLen;
757	                    C2 = C1 + col2;
758	
759	                    NDS_VEC_VSETVLI(vl, mulLen, DEF_VTYPE_SEW, NDS_VEC_VTYPE_LMUL_M2);
760	                    for (k = kk; k < max_kk_tiling_size; k += 8)
761	                    {
762	                        DEF_VLOAD_V(NDS_VEC_V16, B11);
763	                        DEF_VLOAD_V(NDS_VEC_V18, B21);
764	                        DEF_VLOAD_V(NDS_VEC_V20, B31);
765	                        DEF_VLOAD_V(NDS_VEC_V22, B41);
766	                        DEF_VLOAD_V(NDS_VEC_V24, B51);
767	                        DEF_VLOAD_V(NDS_VEC_V26, B61);
768	                        DEF_VLOAD_V(NDS_VEC_V28, B71);
769	                        DEF_VLOAD_V(NDS_VEC_V30, B81);
770	                        MM_TYPE_A tmpa11 = *A11++;
771	                        MM_TYPE_A tmpa21 = *A21++;
772	                        DEF_VMACC_V(NDS_VEC_V0, tmpa11, NDS_VEC_V16);
773	                        DEF_VMACC_V(NDS_VEC_V8, tmpa21, NDS_VEC_V16);
774	
775	                        MM_TYPE_A tmpa12 = *A11++;
776	                        MM_TYPE_A tmpa22 = *A21++;
777	                        DEF_VMACC_V(NDS_VEC_V0, tmpa12, NDS_VEC_V18);
778	                        DEF_VMACC_V(NDS_VEC_V8, tmpa22, NDS_VEC_V18);
779	
780	                        MM_TYPE_A tmpa13 = *A11++;
781	                        MM_TYPE_A tmpa23 = *A21++;
782	                        DEF_VMACC_V(NDS_VEC_V0, tmpa13, NDS_VEC_V20);
783	                        DEF_VMACC_V(NDS_VEC_V8, tmpa23, NDS_VEC_V20);
784	
785	                        MM_TYPE_A tmpa14 = *A11++;
786	                        MM_TYPE_A tmpa24 = *A21++;
787	                        DEF_VMACC_V(NDS_VEC_V0, tmpa14, NDS_VEC_V22);
788	                        DEF_VMACC_V(NDS_VEC_V8, tmpa24, NDS_VEC_V22);
789	
790	                        MM_TYPE_A tmpa15 = *A11++;
791	                        MM_TYPE_A tmpa25 = *A21++;
792	                        DEF_VMACC_V(NDS_VEC_V0, tmpa15, NDS_VEC_V24);
793	                        DEF_VMACC_V(NDS_VEC_V8, tmpa25, NDS_VEC_V24);
794	
795	                        MM_TYPE_A tmpa16 = *A11++;
796	                        MM_TYPE_A tmpa26 = *A21++;
797	                        DEF_VMACC_V(NDS_VEC_V0, tmpa16, NDS_VEC_V26);
798	                        DEF_VMACC_V(NDS_VEC_V8, tmpa26, NDS_VEC_V26);
799	
800	                        MM_TYPE_A tmpa17 = *A11++;
801	                        MM_TYPE_A tmpa27 = *A21++;
802	                        DEF_VMACC_V(NDS_VEC_V0, tmpa17, NDS_VEC_V28);
803	                        DEF_VMACC_V(NDS_VEC_V8, tmpa27, NDS_VEC_V28);
804	
805	                        MM_TYPE_A tmpa18 = *A11++;
806	                        MM_TYPE_A tmpa28 = *A21++;
807	                        DEF_VMACC_V(NDS_VEC_V0, tmpa18, NDS_VEC_V30);
808	                        DEF_VMACC_V(NDS_VEC_V8, tmpa28, NDS_VEC_V30);
809	
810	                        B11 += 8 * col2;
811	                        B21 += 8 * col2;
812	                        B31 += 8 * col2;
813	                        B41 += 8 * col2;
814	                        B51 += 8 * col2;
815	                        B61 += 8 * col2;
816	                        B71 += 8 * col2;
817	                        B81 += 8 * col2;
818	                    }
819	                    for (; k < kk_tiling_size; k++)
820	                    {
821	                        DEF_VLOAD_V(NDS_VEC_V16, B11);
822	                        MM_TYPE_A tmpa11 = *A11++;
823	                        MM_TYPE_A tmpa21 = *A21++;
824	                        DEF_VMACC_V(NDS_VEC_V0, tmpa11, NDS_VEC_V16);
825	                        DEF_VMACC_V(NDS_VEC_V8, tmpa21, NDS_VEC_V16);
826	
827	                        B11 += col2;
828	                    }
829	                    NDS_VEC_VSETVLI(vl, mulLen, DEF_VTYPEVQ_SEW, NDS_VEC_VTYPE_LMUL_M8);
830	                    DEF_VLOADVQ_V(NDS_VEC_V16, C1);
831	                    DEF_VLOADVQ_V(NDS_VEC_V24, C2);
832	
833	                    NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V16);
834	                    NDS_VEC_VADD_VV(NDS_VEC_V8, NDS_VEC_V8, NDS_VEC_V24);
835	
836	                    DEF_VSTOREVQ_V(NDS_VEC_V0, C1);
837	                    DEF_VSTOREVQ_V(NDS_VEC_V8, C2);
838	                    mulLen -= vl;
839	                }
840	            }
841	            for (; r < row; r++)
842	            {
843	                int mulLen = cc_tiling_size - cc;
844	                while (mulLen > 0)
845	                {
846	                    NDS_VEC_VSETVLI(vl, mulLen, DEF_VTYPEVQ_SEW, NDS_VEC_VTYPE_LMUL_M8);
847	                    NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0); //sum
848	                    A11 = A + r * col + kk;
849	                    B11 = B + kk * col2 + cc_tiling_size - mulLen;
850	                    B21 = B11 + col2;
851	                    B31 = B21 + col2;
852	                    B41 = B31 + col2;
853	                    B51 = B41 + col2;
854	                    B61 = B51 + col2;
855	                    B71 = B61 + col2;
856	                    B81 = B71 + col2;
857	                    C1 = C + r * col2 + cc_tiling_size - mulLen;
858	
859	                    NDS_VEC_VSETVLI(vl, mulLen, DEF_VTYPE_SEW, NDS_VEC_VTYPE_LMUL_M2);
860	                    for (k = kk; k < max_kk_tiling_size; k += 8)
861	                    {
862	                        DEF_VLOAD_V(NDS_VEC_V16, B11);
863	                        DEF_VLOAD_V(NDS_VEC_V18, B21);
864	                        DEF_VLOAD_V(NDS_VEC_V20, B31);
865	                        DEF_VLOAD_V(NDS_VEC_V22, B41);
866	                        DEF_VLOAD_V(NDS_VEC_V24, B51);
867	                        DEF_VLOAD_V(NDS_VEC_V26, B61);
868	                        DEF_VLOAD_V(NDS_VEC_V28, B71);
869	                        DEF_VLOAD_V(NDS_VEC_V30, B81);
870	                        MM_TYPE_A tmpa11 = *A11++;
871	                        MM_TYPE_A tmpa12 = *A11++;
872	                        MM_TYPE_A tmpa13 = *A11++;
873	                        MM_TYPE_A tmpa14 = *A11++;
874	                        MM_TYPE_A tmpa15 = *A11++;
875	                        MM_TYPE_A tmpa16 = *A11++;
876	                        MM_TYPE_A tmpa17 = *A11++;
877	                        MM_TYPE_A tmpa18 = *A11++;
878	                        DEF_VMACC_V(NDS_VEC_V0, tmpa11, NDS_VEC_V16);
879	                        DEF_VMACC_V(NDS_VEC_V0, tmpa12, NDS_VEC_V18);
880	                        DEF_VMACC_V(NDS_VEC_V0, tmpa13, NDS_VEC_V20);
881	                        DEF_VMACC_V(NDS_VEC_V0, tmpa14, NDS_VEC_V22);
882	                        DEF_VMACC_V(NDS_VEC_V0, tmpa15, NDS_VEC_V24);
883	                        DEF_VMACC_V(NDS_VEC_V0, tmpa16, NDS_VEC_V26);
884	                        DEF_VMACC_V(NDS_VEC_V0, tmpa17, NDS_VEC_V28);
885	                        DEF_VMACC_V(NDS_VEC_V0, tmpa18, NDS_VEC_V30);
886	
887	                        B11 += 8 * col2;
888	                        B21 += 8 * col2;
889	                        B31 += 8 * col2;
890	                        B41 += 8 * col2;
891	                        B51 += 8 * col2;
892	                        B61 += 8 * col2;
893	                        B71 += 8 * col2;
894	                        B81 += 8 * col2;
895	                    }
896	                    for (; k < kk_tiling_size; k++)
