q7_t *nn_mat_mul_kernel_q7_bias_2sft(const q7_t * src1,
                                     const q7_t * src2,
                                     const uint16_t out_tensor_ch,
                                     const uint16_t col_src1,
                                     const uint16_t pre_rshift,
                                     const uint16_t out_scale,
                                     const uint16_t post_rshift,
                                     const q31_t * bias,
                                     q7_t * out)
{
#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_VEC_INTRINSIC)
    unsigned long vl;
    uint16_t rowCnt = out_tensor_ch;
    q7_t *pOut2 = out + out_tensor_ch;
    long vlenb = NDS_VEC_CSR_GET_VLENB();

#if (__clang__)
    register const long zero asm ("x0") = 0;
#else
    register const long zero asm ("x0");
#endif

    //set SEW for 1st time VMV_S_X
    //LMUL=8 is just for clear v8~v24 (vmv ignores LMUL)
    vl = __riscv_vsetvl_e32m1(1);
    vint32m1_t vZero = __riscv_vundefined_i32m1();
    vZero = __riscv_vand_tu(vZero, vZero, zero, vl);    //const zero for redsum

    rowCnt = out_tensor_ch >> 2;
    while(rowCnt > 0)
    {
        vl = __riscv_vsetvl_e32m2(col_src1);
        vint32m2_t vAcc0 = __riscv_vundefined_i32m2();
        vint32m2_t vAcc1 = __riscv_vundefined_i32m2();
        vint32m2_t vAcc2 = __riscv_vundefined_i32m2();
        vint32m2_t vAcc3 = __riscv_vundefined_i32m2();
        vint32m2_t vAcc4 = __riscv_vundefined_i32m2();
        vint32m2_t vAcc5 = __riscv_vundefined_i32m2();
        vint32m2_t vAcc6 = __riscv_vundefined_i32m2();
        vint32m2_t vAcc7 = __riscv_vundefined_i32m2();
        // setup pointers for two sources
        const q7_t *pB = src2;
        const q7_t *pB2 = pB + col_src1;
        const q7_t *pA2 = src1 + col_src1;
        const q7_t *pA3 = pA2 + col_src1;
        const q7_t *pA4 = pA3 + col_src1;

        //clear v0~v15 (keep multiplication results)
        vAcc0 = __riscv_vand_tu(vAcc0, vAcc0, zero, vl);
        vAcc1 = __riscv_vand_tu(vAcc1, vAcc1, zero, vl);
        vAcc2 = __riscv_vand_tu(vAcc2, vAcc2, zero, vl);
        vAcc3 = __riscv_vand_tu(vAcc3, vAcc3, zero, vl);
        vAcc4 = __riscv_vand_tu(vAcc4, vAcc4, zero, vl);
        vAcc5 = __riscv_vand_tu(vAcc5, vAcc5, zero, vl);
        vAcc6 = __riscv_vand_tu(vAcc6, vAcc6, zero, vl);
        vAcc7 = __riscv_vand_tu(vAcc7, vAcc7, zero, vl);

        unsigned long colCnt = col_src1;
        while(colCnt >= (vlenb * NDS_VEC_VTYPE_LMUL_ID_M2))
        {
            vl = __riscv_vsetvl_e8m2(colCnt);
            //load src1
            vint8m2_t vSrc1_i8 = __riscv_vle8_v_i8m2(src1, vl);
            vint8m2_t vPa2_i8 = __riscv_vle8_v_i8m2(pA2, vl);
            vint8m2_t vPa3_i8 = __riscv_vle8_v_i8m2(pA3, vl);
            vint8m2_t vPa4_i8 = __riscv_vle8_v_i8m2(pA4, vl);
            //load src2
            vint8m2_t vPb_i8 = __riscv_vle8_v_i8m2(pB, vl);
            vint8m2_t vPb2_i8 = __riscv_vle8_v_i8m2(pB2, vl);

            //bump pointers and update loop counter
            colCnt -= vl;
            src1 += vl;
            pA2 += vl;
            pA3 += vl;
            pA4 += vl;
            pB += vl;
            pB2 += vl;

            //set the proper avl/SEW/LMUL values for vd4dot
            vl >>= 2;
            vl = __riscv_vsetvl_e32m2(vl);

            //acc += src1 * src2
            vAcc0 = __riscv_vd4dots_vv_i32m2(vAcc0, vSrc1_i8, vPb_i8, vl);
            vAcc1 = __riscv_vd4dots_vv_i32m2(vAcc1, vSrc1_i8, vPb2_i8, vl);
            vAcc2 = __riscv_vd4dots_vv_i32m2(vAcc2, vPa2_i8, vPb_i8, vl);
            vAcc3 = __riscv_vd4dots_vv_i32m2(vAcc3, vPa2_i8, vPb2_i8, vl);
            vAcc4 = __riscv_vd4dots_vv_i32m2(vAcc4, vPa3_i8, vPb_i8, vl);
            vAcc5 = __riscv_vd4dots_vv_i32m2(vAcc5, vPa3_i8, vPb2_i8, vl);
            vAcc6 = __riscv_vd4dots_vv_i32m2(vAcc6, vPa4_i8, vPb_i8, vl);
            vAcc7 = __riscv_vd4dots_vv_i32m2(vAcc7, vPa4_i8, vPb2_i8, vl);
        }

        //extra process for the case of elements to be dot producted is not a mutiple of 4
        if(colCnt > 0)
        {
            //clean one of the dot product source
            vl = __riscv_vsetvlmax_e8m2();
            vint8m2_t vSrc1_i8 = __riscv_vundefined_i8m2();
            vint8m2_t vPa2_i8 = __riscv_vundefined_i8m2();
            vint8m2_t vPa3_i8 = __riscv_vundefined_i8m2();
            vint8m2_t vPa4_i8 = __riscv_vundefined_i8m2();
            vint8m2_t vPb_i8 = __riscv_vundefined_i8m2();
            vint8m2_t vPb2_i8 = __riscv_vundefined_i8m2();
			vPb_i8 = __riscv_vand_tu(vPb_i8, vPb_i8, 0, vl);
            vPb2_i8 = __riscv_vand_tu(vPb2_i8, vPb2_i8, 0, vl);

            vl = __riscv_vsetvl_e8m2(colCnt);
            //load src1
            vSrc1_i8 = __riscv_vle8_tu(vSrc1_i8, src1, vl);
            vPa2_i8 = __riscv_vle8_tu(vPa2_i8, pA2, vl);
            vPa3_i8 = __riscv_vle8_tu(vPa3_i8, pA3, vl);
            vPa4_i8 = __riscv_vle8_tu(vPa4_i8, pA4, vl);
            //load src2
            vPb_i8 = __riscv_vle8_tu(vPb_i8, pB, vl);
            vPb2_i8 = __riscv_vle8_tu(vPb2_i8, pB2, vl);

            //bump pointers and update loop counter
            // colCnt -= vl;
            // src1 += vl;
            // pA2 += vl;
            // pA3 += vl;
            pA4 += vl;
            // pB += vl;
            // pB2 += vl;

            //set the proper avl/SEW/LMUL values for vd4dot
            //remember to deal with the elements to be dot producted is not a multiple of 4 case
            vl = (vl + 3) >> 2;
            vl = __riscv_vsetvl_e32m2(vl);

            //acc += src1 * src2
            vAcc0 = __riscv_vd4dots_vv_i32m2_tu(vAcc0, vSrc1_i8, vPb_i8, vl);
            vAcc1 = __riscv_vd4dots_vv_i32m2_tu(vAcc1, vSrc1_i8, vPb2_i8, vl);
            vAcc2 = __riscv_vd4dots_vv_i32m2_tu(vAcc2, vPa2_i8, vPb_i8, vl);
            vAcc3 = __riscv_vd4dots_vv_i32m2_tu(vAcc3, vPa2_i8, vPb2_i8, vl);
            vAcc4 = __riscv_vd4dots_vv_i32m2_tu(vAcc4, vPa3_i8, vPb_i8, vl);
            vAcc5 = __riscv_vd4dots_vv_i32m2_tu(vAcc5, vPa3_i8, vPb2_i8, vl);
            vAcc6 = __riscv_vd4dots_vv_i32m2_tu(vAcc6, vPa4_i8, vPb_i8, vl);
            vAcc7 = __riscv_vd4dots_vv_i32m2_tu(vAcc7, vPa4_i8, vPb2_i8, vl);
        }

        vl = __riscv_vsetvl_e32m2(col_src1);    //note the avl here
        vint32m1_t vAcc0_sum = __riscv_vredsum(vAcc0, vZero, vl);
		vint32m1_t vAcc1_sum = __riscv_vredsum(vAcc1, vZero, vl);
        vint32m1_t vAcc2_sum = __riscv_vredsum(vAcc2, vZero, vl);
        vint32m1_t vAcc3_sum = __riscv_vredsum(vAcc3, vZero, vl);
        vint32m1_t vAcc4_sum = __riscv_vredsum(vAcc4, vZero, vl);
        vint32m1_t vAcc5_sum = __riscv_vredsum(vAcc5, vZero, vl);
        vint32m1_t vAcc6_sum = __riscv_vredsum(vAcc6, vZero, vl);
        vint32m1_t vAcc7_sum = __riscv_vredsum(vAcc7, vZero, vl);

        // put the 4 results togher
        vl = __riscv_vsetvl_e32m1(4);
        vAcc0_sum = __riscv_vslideup(vAcc0_sum, vAcc2_sum, 1, vl);
        vAcc0_sum = __riscv_vslideup(vAcc0_sum, vAcc4_sum, 2, vl);
        vAcc0_sum = __riscv_vslideup(vAcc0_sum, vAcc6_sum, 3, vl);
        vAcc1_sum = __riscv_vslideup(vAcc1_sum, vAcc3_sum, 1, vl);
        vAcc1_sum = __riscv_vslideup(vAcc1_sum, vAcc5_sum, 2, vl);
        vAcc1_sum = __riscv_vslideup(vAcc1_sum, vAcc7_sum, 3, vl);

        //load bias
        vint32m1_t vBias_i32 = __riscv_vle32_v_i32m1(bias, vl);
        bias += vl;

        //add bias back
        vAcc0_sum = __riscv_vadd(vAcc0_sum, vBias_i32, vl);
        vAcc1_sum = __riscv_vadd(vAcc1_sum, vBias_i32, vl);

        //1st shift of 2-stage shift
        vAcc0_sum = __riscv_vsra(vAcc0_sum, pre_rshift, vl);
        vAcc1_sum = __riscv_vsra(vAcc1_sum, pre_rshift, vl);

        vAcc0_sum = __riscv_vmul(vAcc0_sum, out_scale, vl);
        vAcc1_sum = __riscv_vmul(vAcc1_sum, out_scale, vl);

        vAcc0_sum = __riscv_vadd(vAcc0_sum, NN_ROUND(post_rshift), vl);
        vAcc1_sum = __riscv_vadd(vAcc1_sum, NN_ROUND(post_rshift), vl);

        //scale down, clip and store the results
        vl = __riscv_vsetvl_e16mf2(4);
        vint16mf2_t vResult0_i16 = __riscv_vnsra(vAcc0_sum, post_rshift, vl);
        vint16mf2_t vResult1_i16 = __riscv_vnsra(vAcc1_sum, post_rshift, vl);
        vl = __riscv_vsetvl_e8mf4(4);
        vint8mf4_t vResult0_i8 = __riscv_vnclip(vResult0_i16, 0, __RISCV_VXRM_RNU, vl);
        vint8mf4_t vResult1_i8 = __riscv_vnclip(vResult1_i16, 0, __RISCV_VXRM_RNU, vl);
        __riscv_vse8(out, vResult0_i8, vl);
        __riscv_vse8(pOut2, vResult1_i8, vl);
        out += vl;
        pOut2 += vl;
        src1 = pA4;
        rowCnt--;
    }

    rowCnt = out_tensor_ch & 3u;
    while(rowCnt > 0)
    {
        /* setup pointers for B */
        const q7_t *pB = src2;
        const q7_t *pB2 = pB + col_src1;

        vl = __riscv_vsetvl_e32m4(col_src1);
        vint32m4_t vAcc0 = __riscv_vundefined_i32m4();
        vint32m4_t vAcc1 = __riscv_vundefined_i32m4();
        vAcc0 = __riscv_vand_tu(vAcc0, vAcc0, zero, vl);
        vAcc1 = __riscv_vand_tu(vAcc1, vAcc1, zero, vl);

        unsigned long colCnt = col_src1;
        while(colCnt >= (vlenb * NDS_VEC_VTYPE_LMUL_ID_M4))
        {
            vl = __riscv_vsetvl_e8m4(colCnt);
            //load src1
            vint8m4_t vSrc1_i8 = __riscv_vle8_v_i8m4(src1, vl);
            //load src2
            vint8m4_t vPb_i8 = __riscv_vle8_v_i8m4(pB, vl);
            vint8m4_t vPb2_i8 = __riscv_vle8_v_i8m4(pB2, vl);

            //bump pointers and update loop counter
            colCnt -= vl;
            src1 += vl;
            pB += vl;
            pB2 += vl;

            //set the proper avl/SEW/LMUL values for vd4dot
            vl >>= 2;
            vl = __riscv_vsetvl_e32m4(vl);

            //acc += src1 * src2
            vAcc0 = __riscv_vd4dots_vv_i32m4(vAcc0, vPb_i8, vSrc1_i8, vl);
            vAcc1 = __riscv_vd4dots_vv_i32m4(vAcc1, vPb2_i8, vSrc1_i8, vl);
        }

        //extra process for the case of elements to be dot producted is not a mutiple of 4
        if(colCnt > 0)
        {
            //clean one of the dot product source
            vl = __riscv_vsetvlmax_e8m4();
            vint8m4_t vSrc1_i8 = __riscv_vundefined_i8m4();
			vSrc1_i8 = __riscv_vand_tu(vSrc1_i8, vSrc1_i8, 0, vl);

            vl = __riscv_vsetvl_e8m4(colCnt);
            //load src1
            vSrc1_i8 = __riscv_vle8_tu(vSrc1_i8, src1, vl);
