#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100)
q7_t *nn_mat_mul_kernel_q7_bias_2sft_unroll4(const q7_t * src1,
                                             const q7_t * src2,
                                             const uint16_t out_tensor_ch,
                                             const uint16_t col_src1,
                                             const uint16_t pre_rshift,
                                             const uint16_t out_scale,
                                             const uint16_t post_rshift,
                                             const q31_t * bias,
                                             q7_t * out)
{
#if defined(ENA_NDS_V5_VEC_DOT_PROD) && (ENA_VEC_INTRINSIC)
    unsigned long vl;
    unsigned long rowCnt = out_tensor_ch >> 2;
    q7_t *pOut2 = out + out_tensor_ch;
    q7_t *pOut3 = out + out_tensor_ch * 2;
    q7_t *pOut4 = out + out_tensor_ch * 3;

    const q7_t *pA = src1;

    vl = __riscv_vsetvl_e32m1(1);
    vint32m1_t vZero = __riscv_vand(__riscv_vundefined_i32m1(), 0x0, vl);     //keep zero for redsum

    while(rowCnt > 0)
    {
        // setup pointers for A
        const q7_t *pA2 = pA + col_src1;
        const q7_t *pA3 = pA + col_src1 * 2;
        const q7_t *pA4 = pA + col_src1 * 3;
        // setup pointers for B
        const q7_t *pB = src2;
        const q7_t *pB2 = pB + col_src1;
        const q7_t *pB3 = pB + col_src1 * 2;
        const q7_t *pB4 = pB + col_src1 * 3;

        vl = __riscv_vsetvlmax_e32m8();

        //init
        //clear v8~v23 (keep multiplication results)
        vint32m8_t vZeroAccumulator1 = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);
        vint32m8_t vZeroAccumulator2 = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);

        vint32m1_t vAccumulator1 = __riscv_vget_i32m1(vZeroAccumulator1, 0);
        vint32m1_t vAccumulator2 = __riscv_vget_i32m1(vZeroAccumulator1, 1);
        vint32m1_t vAccumulator3 = __riscv_vget_i32m1(vZeroAccumulator1, 2);
        vint32m1_t vAccumulator4 = __riscv_vget_i32m1(vZeroAccumulator1, 3);
        vint32m1_t vAccumulator5 = __riscv_vget_i32m1(vZeroAccumulator1, 4);
        vint32m1_t vAccumulator6 = __riscv_vget_i32m1(vZeroAccumulator1, 5);
        vint32m1_t vAccumulator7 = __riscv_vget_i32m1(vZeroAccumulator1, 6);
        vint32m1_t vAccumulator8 = __riscv_vget_i32m1(vZeroAccumulator1, 7);

        vint32m1_t vAccumulator9 = __riscv_vget_i32m1(vZeroAccumulator2, 0);
        vint32m1_t vAccumulator10 = __riscv_vget_i32m1(vZeroAccumulator2, 1);
        vint32m1_t vAccumulator11 = __riscv_vget_i32m1(vZeroAccumulator2, 2);
        vint32m1_t vAccumulator12 = __riscv_vget_i32m1(vZeroAccumulator2, 3);
        vint32m1_t vAccumulator13 = __riscv_vget_i32m1(vZeroAccumulator2, 4);
        vint32m1_t vAccumulator14 = __riscv_vget_i32m1(vZeroAccumulator2, 5);
        vint32m1_t vAccumulator15 = __riscv_vget_i32m1(vZeroAccumulator2, 6);
        vint32m1_t vAccumulator16 = __riscv_vget_i32m1(vZeroAccumulator2, 7);

        unsigned long colCnt = col_src1;
        while(colCnt > 0)
        {
            vl = __riscv_vsetvl_e8m1(colCnt);
            //load src1 and src2
            vint8m1_t vpA_i8m1 = __riscv_vle8_v_i8m1(pA, vl);
            vint8m1_t vpA2_i8m1 = __riscv_vle8_v_i8m1(pA2, vl);
            vint8m1_t vpA3_i8m1 = __riscv_vle8_v_i8m1(pA3, vl);
            vint8m1_t vpA4_i8m1 = __riscv_vle8_v_i8m1(pA4, vl);

            vint8m1_t vpB_i8m1 = __riscv_vle8_v_i8m1(pB, vl);
            vint8m1_t vpB2_i8m1 = __riscv_vle8_v_i8m1(pB2, vl);
            vint8m1_t vpB3_i8m1 = __riscv_vle8_v_i8m1(pB3, vl);
            vint8m1_t vpB4_i8m1 = __riscv_vle8_v_i8m1(pB4, vl);


            //bump pointers and update loop counter
            colCnt -= vl;
            pA += vl;
            pA2 += vl;
            pA3 += vl;
            pA4 += vl;
            pB += vl;
            pB2 += vl;
            pB3 += vl;
            pB4 += vl;

            //set the proper avl/SEW/LMUL values for vd4dot
            vl >>= 2;
            vl = __riscv_vsetvl_e32m1(vl);

            //acc += src1 * src2
            vAccumulator1 = __riscv_vd4dots_vv_i32m1(vAccumulator1, vpA_i8m1, vpB_i8m1, vl);
            vAccumulator2 = __riscv_vd4dots_vv_i32m1(vAccumulator2, vpA2_i8m1, vpB_i8m1, vl);
            vAccumulator3 = __riscv_vd4dots_vv_i32m1(vAccumulator3, vpA3_i8m1, vpB_i8m1, vl);
            vAccumulator4 = __riscv_vd4dots_vv_i32m1(vAccumulator4, vpA4_i8m1, vpB_i8m1, vl);

            vAccumulator5 = __riscv_vd4dots_vv_i32m1(vAccumulator5, vpA_i8m1, vpB2_i8m1, vl);
            vAccumulator6 = __riscv_vd4dots_vv_i32m1(vAccumulator6, vpA2_i8m1, vpB2_i8m1, vl);
            vAccumulator7 = __riscv_vd4dots_vv_i32m1(vAccumulator7, vpA3_i8m1, vpB2_i8m1, vl);

