#if defined(ENA_AGENT_OPT_CONV_HWC_S8_S8_S8_SYM_BIAS_FAST) && defined(ENA_VEC_ISA)
    /* Optimized path: 4-pixel batched im2col + unroll4 matmul.
       Reduces weight memory traffic by 2x vs the 2-pixel path. */
    int16_t i_out_y, i_out_x, i_ker_y, i_ker_x;
    q7_t *pBuffer = (q7_t *)in_tmp_buf;
    q7_t *pOut = out_tensor;
    int pixel_count = 0;
    const uint16_t col_len = in_tensor_ch * ker_dim * ker_dim;

    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
    {
        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
        {
            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
            {
                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
                {
                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
                    {
                        nn_set_zero_s8(pBuffer, sizeof(q7_t) * in_tensor_ch);
                    }
                    else
                    {
                        nn_dup_s8(in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
                    }
                    pBuffer += in_tensor_ch;
                }
            }
            pixel_count++;

            if (pixel_count == 4)
            {
                pOut = nn_mat_mul_kernel_q7_bias_2sft_unroll4(ker_weight,
                    (q7_t *)in_tmp_buf, out_tensor_ch, col_len,
                    pre_rshift, out_scale, post_rshift, bias, pOut);
                pixel_count = 0;
                pBuffer = (q7_t *)in_tmp_buf;
            }
        }
    }

    /* leftover: 2 or 3 remaining pixels -> process pair then single */
    if (pixel_count >= 2)
    {
        pOut = nn_mat_mul_kernel_q7_bias_2sft(ker_weight,
            (q7_t *)in_tmp_buf, out_tensor_ch, col_len,
            pre_rshift, out_scale, post_rshift, bias, pOut);
        pixel_count -= 2;
        if (pixel_count > 0)
        {
            /* shift remaining 1 pixel to start of buffer */
            nn_dup_s8((q7_t *)in_tmp_buf + 2 * col_len, (q7_t *)in_tmp_buf, col_len);
        }
    }

    /* leftover: 1 remaining pixel */
    if (pixel_count == 1)
    {
#if (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_VEC_INTRINSIC)
        {
            unsigned vl;
            const q7_t *p_wt = ker_weight;
            int i;

            vl = __riscv_vsetvl_e32m1(1);
            vint32m1_t vZero = __riscv_vand(__riscv_vundefined_i32m1(), 0x0, vl);

            for (i = 0; i < out_tensor_ch; i++)
            {
                q7_t *p_in = (q7_t *)in_tmp_buf;
                uint16_t colCnt2 = col_len;

                vl = __riscv_vsetvl_e32m8(col_len);
                vint32m8_t vAccumulator = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);

                while (colCnt2 > 0)
                {
                    vl = __riscv_vsetvl_e8m8(colCnt2);
                    vint8m8_t vP_wt = __riscv_vle8_v_i8m8(p_wt, vl);
                    vint8m8_t vP_in = __riscv_vle8_v_i8m8(p_in, vl);
                    colCnt2 -= vl;
                    p_wt += vl;
                    p_in += vl;
                    vl >>= 2;
                    vl = __riscv_vsetvl_e32m8(vl);
                    vAccumulator = __riscv_vd4dots_vv_i32m8(vAccumulator, vP_wt, vP_in, vl);
                }

                vl = __riscv_vsetvl_e32m8(col_len);
                vint32m1_t vSum = __riscv_vredsum(vAccumulator, vZero, vl);

                vl = __riscv_vsetvl_e32m1(1);
                vint32m1_t vBias = __riscv_vle32_v_i32m1(bias, vl);
                vSum = __riscv_vadd(vSum, vBias, vl);
                vSum = __riscv_vsra(vSum, pre_rshift, vl);
                vSum = __riscv_vmul(vSum, out_scale, vl);
                vSum = __riscv_vadd(vSum, NN_ROUND(post_rshift), vl);

                vl = __riscv_vsetvl_e16mf2(1);
                vint16mf2_t vSum_i16 = __riscv_vnsra(vSum, post_rshift, vl);
                vl = __riscv_vsetvl_e8mf4(1);
                vint8mf4_t vOut = __riscv_vnclip(vSum_i16, 0, __RISCV_VXRM_RNU, vl);
                __riscv_vse8(pOut, vOut, vl);
                bias += vl;
                pOut += vl;
            }
        }
#endif
    }

#elif defined(ENA_VEC_ISA) && defined(ENA_TILING)

