/** @file*/

#include "internal_nn_math.h"
#include "riscv_nn_support.h"

uint32_t riscv_nn_conv_sym_get_buffer_size(const uint16_t in_tensor_dim_x,
                                            const uint16_t in_tensor_dim_y,
                                            const uint16_t in_tensor_ch,
                                            const uint16_t out_tensor_ch,
                                            const uint16_t ker_dim_x,
                                            const uint16_t ker_dim_y,
                                            const uint16_t pad_x,
                                            const uint16_t pad_y,
                                            const uint16_t stride_x,
                                            const uint16_t stride_y,
                                            const uint16_t out_tensor_dim_x,
                                            const uint16_t out_tensor_dim_y)
{
    (void) in_tensor_dim_x;
    (void) in_tensor_dim_y;
    (void) pad_x;
    (void) pad_y;
    (void) stride_x;
    (void) stride_y;
    (void) out_tensor_dim_x;
    (void) out_tensor_dim_y;
    uint32_t buf_size = 0;
#if defined(ENA_VEC_ISA) && defined(ENA_TILING) && defined(ENA_8MHVM)
    (void) out_tensor_ch;
    const long align_byte = 64;
    uint32_t tiling_size = 256;
#ifdef DCACHE_SIZE
    int i;
    int tiling_size_arr[] = { 1,8,16,32,64,128,256,512,1024,2048 };
    int max_tile_size_in_cache = sqrt(((DCACHE_SIZE) << 10) / (6 * sizeof(int8_t)));
    for (i = 1; i < sizeof(tiling_size_arr) / sizeof(tiling_size_arr[0]); i++)
    {
        if (tiling_size_arr[i] > max_tile_size_in_cache)
        {
            tiling_size = tiling_size_arr[i - 1];
            break;
        }
    }
#endif
    buf_size = tiling_size * in_tensor_ch * ker_dim_x * ker_dim_y * sizeof(int8_t);
    buf_size += align_byte - 1;
#elif defined(ENA_VEC_ISA) && defined(ENA_TILING)
    const long align_byte = 64;
    uint32_t tiling_size = 256;
#ifdef DCACHE_SIZE
    int i;
    int tiling_size_arr[] = { 1,8,16,32,64,128,256,512,1024,2048 };
    int max_tile_size_in_cache = sqrt(((DCACHE_SIZE) << 10) / (6 * sizeof(int8_t)));
    for (i = 1; i < sizeof(tiling_size_arr) / sizeof(tiling_size_arr[0]); i++)
    {
        if (tiling_size_arr[i] > max_tile_size_in_cache)
        {
            tiling_size = tiling_size_arr[i - 1];
            break;
        }
    }
#endif
    uint32_t buf_A  = tiling_size * in_tensor_ch * ker_dim_x * ker_dim_y * sizeof(int8_t); //tiling version
    buf_A += align_byte - 1;
    uint32_t buf_B = in_tensor_ch * ker_dim_x * ker_dim_y * out_tensor_ch * sizeof(int8_t); //converted src2
    buf_B += align_byte - 1;
    uint32_t buf_C = tiling_size * out_tensor_ch * sizeof(int32_t); //temp buffer for q31 tiling accumulator
    buf_C += align_byte - 1;
    buf_size = buf_A + buf_B + buf_C;
#elif defined(ENA_VEC_ISA) || defined(ENA_DSP_ISA)
    buf_size  = (uint32_t)2 * (in_tensor_ch * ker_dim_x * ker_dim_y + 1); //original ver.
#endif
    return buf_size;
}

